113→suspend fun FragmentActivity.updateDeckConfigsRaw(input: ByteArray): ByteArray {
114→    val output = CollectionManager.withCol { updateDeckConfigsRaw(input) }
115→    undoableOp { OpChanges.parseFrom(output) }
116→    withContext(Dispatchers.Main) { finish() }
117→    return output
118→}
